package com.recettealarm.app;
import android.app.*;import android.content.*;import android.graphics.Typeface;import android.os.*;import android.widget.*;
public class SettingsActivity extends Activity{SharedPreferences sp;EditText glass,repeat;CheckBox vib,screen;
 public void onCreate(Bundle b){super.onCreate(b);sp=getSharedPreferences("settings",0);draw();}
 void draw(){LinearLayout r=UI.root(this);Button back=UI.whiteBtn(this,"← Retour");r.addView(back);back.setOnClickListener(v->finish());r.addView(UI.tv(this,"Paramètres",31,Typeface.BOLD));r.addView(UI.muted(this,"Configure alarmes, mesures et confort cuisine.",15));LinearLayout alarm=UI.section(this);alarm.addView(UI.tv(this,"Alertes & Alarmes",22,Typeface.BOLD));vib=new CheckBox(this);vib.setText("Vibration activée");vib.setTextSize(17);vib.setChecked(sp.getBoolean("vib",true));screen=new CheckBox(this);screen.setText("Garder l'écran allumé en mode cuisine");screen.setTextSize(17);screen.setChecked(sp.getBoolean("screen",true));repeat=UI.number(this,"Répéter alarme après secondes, ex: 30");repeat.setText(""+sp.getInt("repeat",30));alarm.addView(vib);alarm.addView(screen);alarm.addView(repeat);r.addView(alarm);LinearLayout units=UI.section(this);units.addView(UI.tv(this,"Unités de mesure",22,Typeface.BOLD));glass=UI.number(this,"Taille de ton verre en ml, ex: 200");glass.setText(""+sp.getInt("glass",200));units.addView(glass);units.addView(UI.smallCard(this,"Repère : 1 litre = 1000 ml. Si ton verre fait 200 ml, 1 litre = 5 verres."));r.addView(units);Button save=UI.btn(this,"Enregistrer paramètres");r.addView(save);save.setOnClickListener(v->{sp.edit().putBoolean("vib",vib.isChecked()).putBoolean("screen",screen.isChecked()).putInt("repeat",num(repeat,30)).putInt("glass",num(glass,200)).apply();UI.toast(this,"Paramètres sauvegardés ✅");});}
 int num(EditText e,int d){try{return Integer.parseInt(e.getText().toString().trim());}catch(Exception x){return d;}}
}
